func (m *matchersTree) match(meta ConnData) bool {
	if m == nil {

		log.Warn().Msg("Rule matcher is nil")
		return false
	}

	if m.matcher != nil {
		return m.matcher(meta)
	}

	switch m.operator {
	case "or":
		return m.left.match(meta) || m.right.match(meta)
	case "and":
		return m.left.match(meta) && m.right.match(meta)
	default:

		log.Warn().Str("operator", m.operator).Msg("Invalid rule operator")
		return false
	}
}
